import{_ as e,o as i,c as a,a2 as t}from"./chunks/framework.QoSTM79V.js";const h=JSON.parse('{"title":"AI 交付质量门禁","description":"","frontmatter":{},"headers":[],"relativePath":"mango-pmo/rules/05-ai-delivery-quality.md","filePath":"mango-pmo/rules/05-ai-delivery-quality.md"}'),o={name:"mango-pmo/rules/05-ai-delivery-quality.md"};function r(d,l,c,s,n,p){return i(),a("div",null,[...l[0]||(l[0]=[t('<h1 id="ai-交付质量门禁" tabindex="-1">AI 交付质量门禁 <a class="header-anchor" href="#ai-交付质量门禁" aria-label="Permalink to &quot;AI 交付质量门禁&quot;">​</a></h1><h2 id="_1-适用范围" tabindex="-1">1. 适用范围 <a class="header-anchor" href="#_1-适用范围" aria-label="Permalink to &quot;1. 适用范围&quot;">​</a></h2><ul><li>适用于开发、验证、发布、PR、Issue 处理和任务收尾。</li><li>本文件只约束交付行为；代码实现仍遵循对应前端、后端和测试规范。</li></ul><h2 id="_2-必须执行" tabindex="-1">2. 必须执行 <a class="header-anchor" href="#_2-必须执行" aria-label="Permalink to &quot;2. 必须执行&quot;">​</a></h2><ol><li>开工前锁定目标、范围和不处理范围。</li><li>发现新问题时，先判断是否由本次改动引入。</li><li>本次引入的问题必须当前任务修复；非本次问题必须登记 Issue 后回到主线，除非用户重新确认范围。</li><li>根因结论必须有基线和证据；基线包括 <code>main</code>、任务前版本、发布物料或业务消费项目。</li><li>证据必须能定位对象和结果，至少包含代码/配置/数据/日志/请求/截图中的有效项；没有证据只能写推测。</li><li>涉及运行态验收时，必须确认服务真实启动成功，并记录访问地址、后端健康检查、数据库名和账号标识；禁止记录密码、token。</li><li>页面验收必须记录页面路径、菜单入口、操作步骤、测试数据、业务断言、UI 断言、截图、console/network 结果。</li><li>发布后必须验证发布仓库和业务消费入口都能拿到目标版本；模板、starter、CLI 或依赖变更必须给出升版结论和依据。</li><li>变更既有公共能力时，必须说明影响范围、兼容性、验证矩阵和发布策略。</li><li>新增、修改、删除或重构对外能力时，必须同步更新或说明不更新代码、README/使用说明、需求/设计文档、E2E 脚本和测试结果基线。</li><li>E2E 脚本必须覆盖本次交付影响的用户可见入口、关键业务流程、权限/租户/数据权限边界、关键异常或回归场景；只打开页面、接口 200 或无明显报错不能作为完整 E2E 断言。</li><li>测试结果基线必须记录测试命令、环境和版本、数据库名或测试数据集标识、账号/租户标识、通过/失败/阻塞/例外列表、证据路径和相对上一基线的行为变化；禁止记录密码、token、密钥。</li><li>任务结束必须确认无未说明变更、分支状态明确、服务关闭或说明保留原因。</li></ol><h2 id="_2-1-发布升级日志门禁" tabindex="-1">2.1 发布升级日志门禁 <a class="header-anchor" href="#_2-1-发布升级日志门禁" aria-label="Permalink to &quot;2.1 发布升级日志门禁&quot;">​</a></h2><p>发布 Mango npm 包、Maven 物料、CLI、starter、模板或平台级版本前，必须先维护平台级 <code>CHANGELOG.md</code>。</p><p><code>CHANGELOG.md</code> 最新发布段必须写清：</p><ul><li>发布对象和版本。</li><li>新特性和修复。</li><li>业务升级步骤。</li><li>已执行验证。</li></ul><p>发布后必须创建或回填对应 GitHub Release，并保证 Release 正文包含同一组升级信息。</p><p>没有平台级升级日志、没有业务升级步骤、没有验证说明或没有对应 GitHub Release 时，禁止声明发布完成。</p><h2 id="_2-2-多包发布门禁" tabindex="-1">2.2 多包发布门禁 <a class="header-anchor" href="#_2-2-多包发布门禁" aria-label="Permalink to &quot;2.2 多包发布门禁&quot;">​</a></h2><p>同一 release 涉及多个 npm 包、Maven 物料、CLI、starter 或模板时，必须先形成发布批次，按依赖顺序规划共享门禁和逐包动作。</p><p>必须执行：</p><ul><li>批次内共享门禁只跑一次，包括升级日志、GitHub Release、样式聚合、package exports、consumer typecheck、release lock registry check。</li><li>逐包只执行目标包构建、版本存在检查、publish、npm-hosted/npm-group 或 Maven 仓库回查、tarball/产物校验。</li><li>依赖链按被依赖方先发布，例如 <code>grid-widgets -&gt; admin-shell -&gt; admin -&gt; cli</code>。</li><li>同一 release 涉及多个 Maven jar、starter 或 remote-starter 时，必须使用一次 reactor deploy 发布完整批次，例如 <code>scripts/publish-maven-batch.sh &lt;targets...&gt;</code>；禁止对每个目标循环执行 <code>mvn -pl &lt;module&gt; -am deploy</code>。</li><li>Maven 发布后必须复用同一个临时本地仓库做统一拉取验证；默认只对对外消费入口执行 <code>dependency:get -Dtransitive=false</code>，只有验证完整业务消费链路时才启用传递依赖解析。</li><li>发布脚本没有 batch 能力时，禁止直接逐包调用会重复全量门禁的单包命令；必须先完成共享门禁，再使用跳过共享门禁的发布入口，或先补齐 batch 发布入口。</li><li>交付报告必须说明共享门禁只执行一次的命令，以及逐包发布和回查结果。</li></ul><p>禁止：</p><ul><li>同一 release 对每个包重复执行完整 consumer typecheck、全量 workspace build 或完整文档门禁。</li><li>同一 Maven release 对每个 starter 重复发布相同上游模块，或每个 artifact 使用独立空 Maven local repo 重复下载依赖。</li><li>为了省时间跳过发布后仓库回查或 tarball/产物校验。</li></ul><h2 id="_2-3-pr-评审门禁" tabindex="-1">2.3 PR 评审门禁 <a class="header-anchor" href="#_2-3-pr-评审门禁" aria-label="Permalink to &quot;2.3 PR 评审门禁&quot;">​</a></h2><p>评审 PR 前必须先识别 PR 改动内容：</p><ul><li>确认 base、head、最新提交和文件清单。</li><li>按文件和 diff 判断改动类型、影响模块、接口/数据/配置/页面/发布物料变化。</li><li>根据改动类型选择至少 3 个相关专家视角评审，例如 PMO、架构、后端、前端、QA、安全、支付、发布或文档治理。</li><li>专家评审必须输出阻断问题、非阻断建议和结论。</li><li>存在阻断问题时不得合并；必须把问题登记到 PR 评论或评审结论中。</li><li>无阻断问题时，合并前必须记录评审视角、验证命令、未验证项和风险。</li><li>对外能力变更的 PR 门禁必须检查交付台账中 E2E 脚本和测试结果基线是否填写可复核路径，或有明确 <code>EXCEPTION</code> 依据。</li></ul><p>前端官方模块、admin 聚合入口、CLI 模块清单或样式发布物料发生变化时，PR 门禁必须包含：</p><ul><li><code>pnpm admin:styles:check</code></li><li><code>pnpm admin:module-styles:check</code></li></ul><p>任一检查失败时不得提交 PR 或合并。</p><h2 id="_3-验收判定" tabindex="-1">3. 验收判定 <a class="header-anchor" href="#_3-验收判定" aria-label="Permalink to &quot;3. 验收判定&quot;">​</a></h2><ul><li><code>PASS</code>：服务启动、真实链路、业务断言、UI 断言、异常检查和证据全部满足。</li><li><code>FAIL</code>：功能错误、UI 明显异常，或 console/network 存在未解释错误。</li><li><code>BLOCKED</code>：服务、数据库、账号、权限或依赖环境不可用。</li><li><code>EXCEPTION</code>：必须有用户确认依据和风险说明。</li></ul><h2 id="_4-禁止事项" tabindex="-1">4. 禁止事项 <a class="header-anchor" href="#_4-禁止事项" aria-label="Permalink to &quot;4. 禁止事项&quot;">​</a></h2><ul><li>禁止服务未启动仍声明浏览器验收通过。</li><li>禁止把 404、空菜单、错误页或错误截图当作通过证据。</li><li>禁止未对比基线就断定问题不是本次引入。</li><li>禁止把 Mango 主框架、企业模板项目、业务仿真项目和历史生成项目混作同一个验证对象。</li><li>禁止在修复中重写既有框架壳层、菜单、页签、消息入口等公共能力。</li><li>禁止模板、starter、前端包或后端依赖变更后不判断是否需要升版发布。</li><li>禁止发布、验证、提交或清理只做一半就声明完成。</li></ul>',27)])])}const m=e(o,[["render",r]]);export{h as __pageData,m as default};
